const _wh = $('Webhook').first().json;
const p = _wh.body ?? _wh;

const settingsMap = {};
try {
  $('Settings').all().forEach(item => {
    const key = item.json.key || item.json.col_1 || '';
    const val = item.json.value || item.json.col_2 || '';
    if (key) settingsMap[key.trim()] = String(val).trim();
  });
} catch (e) {}

const TEMPLATE_NO_CREDIT_ID          = settingsMap['ses_template_no_credit']          || '1Ytn9wssFM-Eg_Fy_CXoZ2CKfd-4uamP39tkhrhf5JMs';
const TEMPLATE_NO_CREDIT_NO_IMG_ID   = settingsMap['ses_template_no_credit_no_img']   || '1LGbc5siAxP6zg4B87KpInSzHGDK0hYy8bbNDvrPNcp0';
const TEMPLATE_WITH_CREDIT_ID        = settingsMap['ses_template_with_credit']        || '15cW_pHFAmXfHgZ6w2Tv_NZYRDTQnE0eV4l6nnbdsfc4';
const TEMPLATE_WITH_CREDIT_NO_IMG_ID = settingsMap['ses_template_with_credit_no_img'] || '1bbW_s6qWlfrjKlmuhheiFCDRusPvbRZi7wz3E0B1DkA';
const DRIVE_PARENT_FOLDER_ID         = settingsMap['ses_drive_folder']                || '1QSNGUZ9e7CAyeZNMJ3EpEUuyXTaSfTky';

const creditEnabled = p.credit === 'yes';
const hasImage      = p.has_image !== 'no';
let templateDocId;
if (creditEnabled) {
  templateDocId = hasImage ? TEMPLATE_WITH_CREDIT_ID : TEMPLATE_WITH_CREDIT_NO_IMG_ID;
} else {
  templateDocId = hasImage ? TEMPLATE_NO_CREDIT_ID : TEMPLATE_NO_CREDIT_NO_IMG_ID;
}

// template_vars вже розраховані браузером (calculate-engine.js)
const templateVars = p.template_vars || {};

return [{
  json: {
    templateDocId,
    driveFolderId:  DRIVE_PARENT_FOLDER_ID,
    fileName:       p.file_name     || ('KP_' + (p.project_name || 'Project') + '.pdf'),
    docCopyName:    p.doc_copy_name || ('Proposal_' + Date.now()),
    templateVars,
    chatId:         p.chat_id,
    manager:        p.manager,
    dcKW:           p.dc_kw,
    projectName:    p.project_name,
    region:         p.region,
    managerPhone:   p.manager_phone,
    managerEmail:   p.manager_email,
  }
}];

/* ================================================================
   n8n Code Node — Генерація графіків КП СЕС

   Запускається ПІСЛЯ вузла "Code: Calculate"

   ВХІД:
     $('Code: Calculate').first().json  — результат розрахунку

   ВИХІД:
     year_chart_url  — URL QuickChart.io для річного графіка
     day_chart_url   — URL QuickChart.io для денного графіка
     yearly_gen_kwh  — річна генерація (кВт·год)
     yearly_gen_mwh  — річна генерація (МВт·год, округлено)

   QuickChart.io: https://quickchart.io/chart?c=<JSON>
   Безкоштовний, повертає PNG 800×400.
================================================================ */

// ────────────────────────────────────────────────────────────────
// 1. МІСЯЧНІ КОЕФІЦІЄНТИ ГЕНЕРАЦІЇ (кВт·год на 1 кВт DC за місяць)
//    Джерело: PVGis / SODA MERRA-2 дані для України
//    Порядок: Січ, Лют, Бер, Квіт, Трав, Черв, Лип, Серп, Вер, Жовт, Лис, Груд
// ────────────────────────────────────────────────────────────────

const MONTHLY_COEF = {
  // Північ
  'Чернігівська область':     [22, 33, 65, 98, 118, 120, 122, 113, 85, 50, 24, 17],
  'Сумська область':          [23, 34, 66, 99, 119, 121, 123, 114, 86, 51, 25, 18],
  'Житомирська область':      [24, 35, 67, 100, 120, 122, 124, 115, 87, 52, 25, 18],

  // Захід
  'Волинська область':        [24, 36, 67, 100, 119, 120, 122, 112, 85, 51, 25, 17],
  'Рівненська область':       [24, 36, 68, 101, 120, 121, 123, 113, 86, 52, 25, 18],
  'Львівська область':        [26, 38, 72, 106, 123, 124, 127, 118, 90, 56, 27, 19],
  'Закарпатська область':     [30, 44, 80, 113, 130, 131, 135, 126, 98, 62, 31, 22],
  'Івано-Франківська область':[27, 40, 74, 107, 124, 125, 128, 119, 91, 57, 28, 20],
  'Тернопільська область':    [26, 38, 71, 105, 122, 123, 126, 117, 89, 55, 26, 18],
  'Хмельницька область':      [26, 38, 71, 105, 122, 123, 126, 117, 89, 55, 26, 18],
  'Вінницька область':        [27, 40, 74, 108, 126, 127, 130, 120, 92, 57, 27, 19],
  'Чернівецька область':      [28, 42, 78, 112, 129, 130, 134, 125, 96, 60, 29, 21],

  // Центр
  'м. Київ':                  [25, 37, 71, 105, 124, 126, 128, 118, 89, 53, 25, 18],
  'Київська область':         [25, 37, 70, 104, 123, 125, 127, 117, 88, 52, 25, 17],
  'Черкаська область':        [28, 42, 78, 112, 131, 133, 135, 125, 95, 58, 27, 19],
  'Полтавська область':       [29, 43, 79, 114, 133, 135, 137, 127, 97, 60, 28, 20],
  'Кіровоградська область':   [31, 47, 85, 119, 138, 140, 143, 133, 103, 64, 30, 22],

  // Схід
  'Харківська область':       [28, 43, 80, 114, 133, 135, 138, 128, 97, 59, 27, 19],
  'Дніпропетровська область': [32, 49, 87, 122, 141, 143, 146, 136, 105, 66, 31, 22],
  'Донецька область':         [30, 46, 84, 118, 137, 139, 142, 132, 101, 63, 30, 21],
  'Запорізька область':       [35, 53, 95, 131, 150, 152, 156, 145, 113, 72, 34, 25],
  'Луганська область':        [29, 44, 81, 115, 134, 136, 139, 129, 98, 60, 28, 20],

  // Південь
  'Одеська область':          [38, 57, 100, 137, 156, 158, 163, 151, 118, 76, 37, 27],
  'Миколаївська область':     [36, 55, 98, 134, 153, 155, 160, 148, 115, 73, 35, 26],
  'Херсонська область':       [37, 56, 100, 136, 155, 157, 162, 150, 117, 75, 36, 26],

  // Default (середня Україна якщо регіон не знайдено)
  'default':                  [28, 42, 77, 111, 130, 132, 134, 124, 95, 59, 28, 19],
};

const MONTHS_UK = ['Січ', 'Лют', 'Бер', 'Квіт', 'Трав', 'Черв', 'Лип', 'Серп', 'Вер', 'Жовт', 'Лис', 'Груд'];

// Денні коефіцієнти (частки від добового максимуму) — типовий літній день
// Кожна точка = година (0..23), відносна частка генерації 0..1
const DAILY_HOURLY_PROFILE = [
  0, 0, 0, 0, 0, 0.03,    // 0-5 год
  0.08, 0.18, 0.38, 0.58, 0.75, 0.88,  // 6-11 год
  0.97, 1.00, 0.97, 0.88, 0.75, 0.58,  // 12-17 год
  0.35, 0.15, 0.05, 0.01, 0, 0,         // 18-23 год
];

// ────────────────────────────────────────────────────────────────
// 2. ВХІДНІ ДАНІ
// ────────────────────────────────────────────────────────────────

const calc = $('Code: Calculate').first().json;

const dcKW      = parseFloat(calc.dc_kw)  || 0;
const region    = calc.region || 'default';
const tariffNow = parseFloat(calc.tariff_now) || 0;
const creditEnabled = calc.credit_enabled || false;
const creditMonths  = parseInt(calc.credit_months) || 60;
const monthlyPaymentUAH = parseFloat(calc.monthly_payment_uah) || 0;
const monthlySavingsUAH = parseFloat(calc.monthly_savings_uah) || 0;

const coefs = MONTHLY_COEF[region] || MONTHLY_COEF['default'];

// ────────────────────────────────────────────────────────────────
// 3. МІСЯЧНА ГЕНЕРАЦІЯ (кВт·год)
// ────────────────────────────────────────────────────────────────

const monthlyKWh = coefs.map(c => Math.round(c * dcKW));
const yearlyKWh  = monthlyKWh.reduce((s, v) => s + v, 0);
const yearlyMWh  = Math.round(yearlyKWh / 100) / 10; // 1 знак після коми

// Пік — найкращий місяць
const peakIdx  = monthlyKWh.indexOf(Math.max(...monthlyKWh));
const peakKWh  = monthlyKWh[peakIdx];

// ────────────────────────────────────────────────────────────────
// 4. ДЕННА ГЕНЕРАЦІЯ (для пікового місяця)
//    Беремо денну генерацію пікового місяця та розподіляємо по годинах
// ────────────────────────────────────────────────────────────────

// Середньодобова генерація для пікового місяця (кВт·год/день)
const daysInPeakMonth = [31, 28, 31, 30, 31, 30, 31, 31, 30, 31, 30, 31][peakIdx];
const dailyAvgKWh     = peakKWh / daysInPeakMonth;

// Профіль дня (кВт·год за годину)
const dailyHourlyKWh  = DAILY_HOURLY_PROFILE.map(factor => +(factor * dailyAvgKWh).toFixed(1));

// Години для підписів (тільки денні)
const hourLabels = Array.from({ length: 24 }, (_, i) => `${i}:00`);

// ────────────────────────────────────────────────────────────────
// 5. QUICKCHART.IO — РІЧНИЙ ГРАФІК
// ────────────────────────────────────────────────────────────────

const yearChartConfig = {
  type: 'bar',
  data: {
    labels: MONTHS_UK,
    datasets: [{
      label: 'Генерація, кВт·год',
      data: monthlyKWh,
      backgroundColor: monthlyKWh.map((_, i) =>
        i === peakIdx ? '#FFC400' : '#4A90D9'
      ),
      borderRadius: 6,
    }],
  },
  options: {
    plugins: {
      legend:  { display: false },
      title:   {
        display: true,
        text:    `Річна генерація СЕС ${dcKW.toFixed(0)} кВт · ${region}`,
        font:    { size: 14 },
      },
      datalabels: {
        anchor: 'end',
        align:  'top',
        font:   { size: 10 },
        formatter: (v) => v >= 1000 ? `${(v/1000).toFixed(1)}МВт` : `${v}`,
      },
    },
    scales: {
      y: {
        beginAtZero: true,
        title: { display: true, text: 'кВт·год' },
        grid: { color: '#f0f0f0' },
      },
      x: { grid: { display: false } },
    },
  },
};

// ────────────────────────────────────────────────────────────────
// 6. QUICKCHART.IO — ДЕННИЙ ГРАФІК
// ────────────────────────────────────────────────────────────────

const dayChartConfig = {
  type: 'line',
  data: {
    labels: hourLabels,
    datasets: [{
      label: `Генерація (${MONTHS_UK[peakIdx]}, кВт·год/год)`,
      data: dailyHourlyKWh,
      borderColor: '#FFC400',
      backgroundColor: 'rgba(255,196,0,0.15)',
      borderWidth: 2.5,
      pointRadius: 3,
      fill: true,
      tension: 0.4,
    }],
  },
  options: {
    plugins: {
      legend: { display: false },
      title: {
        display: true,
        text:    `Денна генерація (${MONTHS_UK[peakIdx]}, середній день) · СЕС ${dcKW.toFixed(0)} кВт`,
        font:    { size: 14 },
      },
    },
    scales: {
      y: {
        beginAtZero: true,
        title: { display: true, text: 'кВт·год/год' },
        grid:  { color: '#f0f0f0' },
      },
      x: {
        grid: { display: false },
        ticks: { maxTicksLimit: 12 },
      },
    },
  },
};

// ────────────────────────────────────────────────────────────────
// 7. ФОРМУВАННЯ URL QUICKCHART
// ────────────────────────────────────────────────────────────────

function toChartUrl(config, width = 800, height = 380) {
  const json = encodeURIComponent(JSON.stringify(config));
  return `https://quickchart.io/chart?w=${width}&h=${height}&bkg=white&c=${json}`;
}

const yearChartUrl = toChartUrl(yearChartConfig);
const dayChartUrl  = toChartUrl(dayChartConfig);

// ────────────────────────────────────────────────────────────────
// 8. ЕКОНОМІКА (беремо з ses_calculate, доповнюємо точною генерацією)
// ────────────────────────────────────────────────────────────────

// Точна річна економія на основі регіональних даних
const selfConsumptionRatio = 0.80;
const yearlyEconomyUAH     = tariffNow > 0
  ? Math.round(yearlyKWh * selfConsumptionRatio * tariffNow)
  : Math.round(calc.monthly_savings_uah * 12) || 0;

// ────────────────────────────────────────────────────────────────
// 9. ВИХІД
// ────────────────────────────────────────────────────────────────

return [{
  json: {
    // Передаємо все з попереднього вузла
    ...calc,

    // Графіки
    year_chart_url: yearChartUrl,
    day_chart_url:  dayChartUrl,

    // Генерація
    monthly_kwh:    monthlyKWh,
    yearly_kwh:     yearlyKWh,
    yearly_mwh:     yearlyMWh,
    peak_month:     MONTHS_UK[peakIdx],

    // Економіка (уточнена з регіональними даними)
    yearly_kwh:     yearlyKWh,
    yearly_mwh:     yearlyMWh,
    yearly_economy: yearlyEconomyUAH,
    peak_month:     MONTHS_UK[peakIdx],

    // Перерахунок окупності з регіональними даними
    // (точніше ніж fallback 1100 год/рік у ses_calculate)
    ...(() => {
      const totalUAH = (parseFloat(calc.total_usd) || 0) * (parseFloat(calc.rate_usd) || 41.2);
      let paybackStr = '—';
      if (yearlyEconomyUAH > 0 && totalUAH > 0) {
        const py    = totalUAH / yearlyEconomyUAH;
        const pyInt = Math.floor(py);
        const pyMon = Math.round((py - pyInt) * 12);
        paybackStr  = pyMon > 0 ? `${pyInt} р. ${pyMon} міс.` : `${pyInt} р.`;
      }
      return {
        payback_str_regional: paybackStr,
        template_vars: {
          ...calc.template_vars,
          '{{yearly_gen}}':   `${yearlyMWh} МВт·год`,
          '{{payback}}':      paybackStr,
          '{{tariff_now}}':   tariffNow ? `${tariffNow.toFixed(2)} грн/кВт·год` : calc.template_vars?.['{{tariff_now}}'] || '',
          '{{total_profit}}': `${Math.round(yearlyEconomyUAH / 1000)} тис. грн/рік`,
        },
      };
    })(),
  }
}];

/* ================================================================
   n8n Code Node — Завантаження кастомного зображення в Google Drive

   Запускається після "Code: Charts" лише якщо є custom_image_base64.
   В n8n: використовуй IF вузол перед цим кодом:
     IF {{ $json.has_custom_image }} === true → цей вузол
     ELSE → одразу до "Drive: Copy Template"

   ВХІД:  $('Code: Charts').first().json
   ВИХІД: всі поля + custom_image_drive_id, custom_image_drive_url

   Після цього вузла — вузол "Drive: Upload Image" або
   використовуємо HTTP Request до Drive API напряму.
================================================================ */

const data = $('Code: Charts').first().json;

// Якщо немає зображення — просто пропускаємо (не повинно сюди потрапити через IF)
if (!data.has_custom_image || !data.custom_image_base64) {
  return [{ json: { ...data, custom_image_drive_id: null, custom_image_drive_url: null } }];
}

// Декодуємо base64 → бінарний буфер
const base64 = data.custom_image_base64;
const mime   = data.custom_image_mime || 'image/jpeg';
const ext    = mime.split('/')[1] || 'jpg';
const fileName = `viz_${data.project_name || 'ses'}_${Date.now()}.${ext}`;

// Конвертуємо base64 у Buffer для n8n бінарного виводу
const buffer = Buffer.from(base64, 'base64');

// Повертаємо як бінарні дані — наступний вузол "Drive: Upload" їх завантажить
return [{
  json: {
    ...data,
    image_file_name: fileName,
    image_mime:      mime,
  },
  binary: {
    customImage: {
      data:     base64,
      mimeType: mime,
      fileName: fileName,
    }
  }
}];

/* ================================================================
   ПІСЛЯ ЦЬОГО ВУЗЛА в n8n:

   [Drive: Upload Image]
   - Operation: Upload
   - Parent Folder: {{ $json.driveFolderId }}  (або окрема папка)
   - File Name: {{ $json.image_file_name }}
   - Binary Property: customImage
   → Отримуємо: id, webViewLink, webContentLink

   Потім зберігаємо Drive ID і передаємо далі для вставки в Docs.

   [Code: Merge Image URL]
   const prevData = $('Code: Charts').first().json;  // або передати через попередні
   const driveFile = $('Drive: Upload Image').first().json;
   return [{
     json: {
       ...prevData,
       custom_image_drive_id:  driveFile.id,
       // Drive URL для публічного доступу (файл має бути shared: anyone with link):
       custom_image_drive_url: `https://drive.google.com/uc?export=view&id=${driveFile.id}`,
     }
   }];

   [HTTP: Share Image Publicly]  (зробити файл публічним)
   - Method: POST
   - URL: https://www.googleapis.com/drive/v3/files/{{ $json.custom_image_drive_id }}/permissions
   - Auth: Google OAuth2
   - Body: { "role": "reader", "type": "anyone" }

   Після цього — вставляємо зображення в Doc через insertInlineImage.
================================================================ */

// Об'єднання гілок: з custom image або без
const calc = $('Code: Charts').first().json;

let customImageDriveId  = null;
let customImageDriveUrl = null;

try {
  const imageItems = $('Drive: Upload Custom Image').all();
  if (imageItems.length > 0) {
    customImageDriveId  = imageItems[0].json.id;
    customImageDriveUrl = `https://drive.google.com/uc?export=view&id=${customImageDriveId}`;
  }
} catch (e) {
  // Вузол не виконувався (гілка без зображення) — залишаємо null
}

return [{
  json: {
    ...calc,
    custom_image_drive_id:  customImageDriveId,
    custom_image_drive_url: customImageDriveUrl,
  }
}];

// Google Docs з вкладками: контент у tabs[0].documentTab.body.content
// Або у body.content для старих документів
const tab0Content = $json.tabs?.[0]?.documentTab?.body?.content || [];
const bodyContent = $json.body?.content || [];
const content = tab0Content.length > 0 ? tab0Content : bodyContent;

let startIndex = null;
let endIndex   = null;

for (let i = 0; i < content.length; i++) {
  const el = content[i];
  if (!el.paragraph || !el.paragraph.elements) continue;
  const text = el.paragraph.elements
    .map(e => (e.textRun?.content || '').trim().toLowerCase())
    .join('');
  if (text === 'вкладка 1') {
    startIndex = el.startIndex;
  } else if (startIndex !== null && text !== '') {
    endIndex = el.startIndex;
    break;
  }
}

const calc  = $('Code: Після гілки зображення').first().json;
const docId = $('Drive: Копіювати шаблон').first().json.id;

const deleteRequests = (startIndex !== null && endIndex !== null)
  ? [{ deleteContentRange: { range: { startIndex, endIndex: endIndex - 1 } } }]
  : [];

return [{ json: { docId, deleteRequests, ...calc } }];

const calc  = $('Code: Після гілки зображення').first().json;
const docId = $('Drive: Копіювати шаблон').first().json.id;
const vars  = calc.template_vars;

const requests = Object.entries(vars).map(([tag, value]) => ({
  replaceAllText: {
    containsText: { text: tag, matchCase: true },
    replaceText:  String(value ?? ''),
  }
}));

return [{
  json: {
    docId,
    requests,
    chat_id:       calc.chat_id,
    file_name:     calc.file_name,
    project_name:  calc.project_name,
    power_label:   calc.power_label,
    total_display: calc.total_display,
    currency_sign: calc.currency_sign,
    driveFolderId: calc.driveFolderId,
  }
}];

// Після replaceAllText порожні рядки таблиці містять лише пусті рядки.
// Видаляємо їх знизу вверх, щоб уникнути зміщення індексів.
const docData = $json;
const calc    = $('Code: Підготовка Docs').first().json;
const docId   = calc.docId;

const content = docData.tabs?.[0]?.documentTab?.body?.content || docData.body?.content || [];

const requests = [];

for (const el of content) {
  if (!el.table) continue;

  // Обробляємо лише таблицю специфікації — ту що містить "ОБЛАДНАННЯ ТА МАТЕРІАЛИ"
  // (в документі є декілька таблиць з пустими рядками — структурні, видаляти не треба)
  const isCostTable = el.table.tableRows.some(row => {
    const firstCell = (row.tableCells[0]?.content || [])
      .flatMap(p => (p.paragraph?.elements || []))
      .map(e => e.textRun?.content || '')
      .join('')
      .trim();
    return firstCell.includes('ОБЛАДНАННЯ');
  });
  if (!isCostTable) continue;

  const tableStartIndex = el.startIndex;
  const emptyRowIndices = [];

  el.table.tableRows.forEach((row, rowIndex) => {
    const allEmpty = row.tableCells.every(cell => {
      const cellText = (cell.content || [])
        .flatMap(p => (p.paragraph?.elements || []))
        .map(e => e.textRun?.content || '')
        .join('')
        .trim();
      return cellText === '';
    });
    if (allEmpty) emptyRowIndices.push(rowIndex);
  });

  // Видаляємо з кінця, щоб не зміщувати індекси попередніх рядків
  for (let i = emptyRowIndices.length - 1; i >= 0; i--) {
    requests.push({
      deleteTableRow: {
        tableCellLocation: {
          tableStartLocation: { index: tableStartIndex },
          rowIndex: emptyRowIndices[i],
          columnIndex: 0,
        },
      },
    });
  }
}

// DEBUG — видалити після перевірки
const _tables = content.filter(el => el.table);
const _debugRows = _tables.map((el, ti) => ({
  tableIndex: ti,
  tableStartIndex: el.startIndex,
  rowCount: el.table.tableRows.length,
  rows: el.table.tableRows.map((row, ri) => ({
    rowIndex: ri,
    cells: row.tableCells.map(cell =>
      (cell.content || [])
        .flatMap(p => (p.paragraph?.elements || []))
        .map(e => e.textRun?.content || '')
        .join('')
        .trim()
    ),
  })),
}));

return [{ json: { docId, ...calc, requests, _debug_empty_rows: { tables_count: _tables.length, requests_count: requests.length, tables: _debugRows } } }];
